CREATE TABLE IF NOT EXISTS leads (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),company_name VARCHAR(255) NOT NULL,contact_name VARCHAR(255),email VARCHAR(255),phone VARCHAR(50),industry VARCHAR(50),city VARCHAR(100),country VARCHAR(100) DEFAULT 'Deutschland',website_url VARCHAR(500),linkedin_url VARCHAR(500),instagram_url VARCHAR(500),facebook_url VARCHAR(500),employee_count INTEGER,lead_source VARCHAR(50),status VARCHAR(50) DEFAULT 'new',preferred_language VARCHAR(10) DEFAULT 'de',company_id UUID,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS customers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),lead_id UUID,company_name VARCHAR(255) NOT NULL,contact_name VARCHAR(255),email VARCHAR(255),phone VARCHAR(50),services_purchased JSONB DEFAULT '[]',monthly_revenue DECIMAL(10,2) DEFAULT 0,setup_fee_paid DECIMAL(10,2) DEFAULT 0,start_date DATE,renewal_date DATE,contract_status VARCHAR(20) DEFAULT 'active',health_score VARCHAR(10) DEFAULT 'green',preferred_language VARCHAR(10) DEFAULT 'de',invoice_language VARCHAR(10) DEFAULT 'de',account_manager VARCHAR(255),company_id UUID,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS opportunities (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),lead_id UUID,problem_identified TEXT,service_type VARCHAR(50),potential_monthly_revenue DECIMAL(10,2),priority VARCHAR(20) DEFAULT 'medium',status VARCHAR(50) DEFAULT 'open',communication_language VARCHAR(10) DEFAULT 'de',company_id UUID,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS communications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),lead_id UUID,customer_id UUID,contact_name VARCHAR(255),type VARCHAR(50),direction VARCHAR(20),language_used VARCHAR(10),template_key VARCHAR(100),summary TEXT,next_action TEXT,follow_up_date DATE,company_id UUID,communicated_at TIMESTAMPTZ DEFAULT NOW(),created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS proposals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),lead_id UUID,proposal_date DATE DEFAULT CURRENT_DATE,services_offered JSONB DEFAULT '[]',document_language VARCHAR(10) DEFAULT 'de',setup_fee DECIMAL(10,2) DEFAULT 0,monthly_fee DECIMAL(10,2) DEFAULT 0,status VARCHAR(50) DEFAULT 'draft',contract_signed BOOLEAN DEFAULT FALSE,legal_jurisdiction VARCHAR(20) DEFAULT 'DE',company_id UUID,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS financial_tracking (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),month DATE NOT NULL UNIQUE,new_customers INTEGER DEFAULT 0,churned_customers INTEGER DEFAULT 0,new_mrr_added DECIMAL(10,2) DEFAULT 0,mrr_lost DECIMAL(10,2) DEFAULT 0,total_mrr DECIMAL(10,2) DEFAULT 0,setup_fees_collected DECIMAL(10,2) DEFAULT 0,total_revenue DECIMAL(10,2) DEFAULT 0,expenses DECIMAL(10,2) DEFAULT 0,net_profit DECIMAL(10,2) DEFAULT 0,company_id UUID,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());

CREATE TABLE IF NOT EXISTS i18n_translations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),key VARCHAR(100) NOT NULL,category VARCHAR(50) NOT NULL,lang_de TEXT,lang_en TEXT,lang_tr TEXT,lang_ar TEXT,lang_fr TEXT,lang_pl TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(key,category));
CREATE TABLE IF NOT EXISTS message_templates (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),template_key VARCHAR(100) NOT NULL,language VARCHAR(10) NOT NULL,channel VARCHAR(20) NOT NULL,subject TEXT,body TEXT NOT NULL,variables JSONB DEFAULT '[]',is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(template_key,language,channel));
CREATE TABLE IF NOT EXISTS services (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),service_key VARCHAR(50) NOT NULL UNIQUE,name_de VARCHAR(255),name_en VARCHAR(255),name_tr VARCHAR(255),name_ar VARCHAR(255),description_de TEXT,description_en TEXT,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS service_packages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),service_key VARCHAR(50) NOT NULL,package_name_de VARCHAR(255),package_name_en VARCHAR(255),setup_fee_min DECIMAL(10,2),setup_fee_max DECIMAL(10,2),monthly_fee_min DECIMAL(10,2),monthly_fee_max DECIMAL(10,2),target_client_de TEXT,target_client_en TEXT,is_active BOOLEAN DEFAULT TRUE,sort_order INTEGER DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW());

CREATE TABLE IF NOT EXISTS companies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name VARCHAR(255) NOT NULL,legal_name VARCHAR(255),registration_number VARCHAR(100),tax_number VARCHAR(100),vat_id VARCHAR(50),iban VARCHAR(50),bic VARCHAR(20),company_type VARCHAR(20) DEFAULT 'own',country VARCHAR(100) DEFAULT 'Deutschland',state VARCHAR(100),city VARCHAR(100),zip_code VARCHAR(20),address_line1 VARCHAR(255),address_line2 VARCHAR(255),phone VARCHAR(50),email VARCHAR(255),website VARCHAR(500),industry VARCHAR(50),preferred_language VARCHAR(10) DEFAULT 'de',invoice_language VARCHAR(10) DEFAULT 'de',currency VARCHAR(10) DEFAULT 'EUR',is_active BOOLEAN DEFAULT TRUE,notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
