CREATE TABLE IF NOT EXISTS document_sequences (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),document_type VARCHAR(50) NOT NULL,prefix VARCHAR(20) NOT NULL,year INTEGER NOT NULL,last_number INTEGER DEFAULT 0,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW(),UNIQUE(document_type,year));
