CREATE TABLE IF NOT EXISTS documents (id UUID PRIMARY KEY DEFAULT gen_random_uuid(),document_number VARCHAR(50) NOT NULL UNIQUE,document_type VARCHAR(50) NOT NULL,file_format VARCHAR(20) NOT NULL DEFAULT 'pdf',title VARCHAR(255) NOT NULL,version INTEGER DEFAULT 1,status VARCHAR(50) DEFAULT 'draft',language VARCHAR(10) DEFAULT 'de',company_id UUID,lead_id UUID,customer_id UUID,file_url TEXT,file_name VARCHAR(255),file_size_bytes BIGINT,mime_type VARCHAR(100) DEFAULT 'application/pdf',storage_provider VARCHAR(50),storage_bucket VARCHAR(255),storage_key TEXT,amount_net DECIMAL(10,2),amount_tax DECIMAL(10,2),amount_gross DECIMAL(10,2),currency VARCHAR(10) DEFAULT 'EUR',tax_rate DECIMAL(5,2) DEFAULT 19.00,generated_by VARCHAR(100),sent_at TIMESTAMPTZ,signed_at TIMESTAMPTZ,expires_at TIMESTAMPTZ,archived_at TIMESTAMPTZ,tags JSONB DEFAULT '[]',notes TEXT,created_at TIMESTAMPTZ DEFAULT NOW(),updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_documents_type ON documents(document_type);
CREATE INDEX IF NOT EXISTS idx_documents_status ON documents(status);
CREATE INDEX IF NOT EXISTS idx_documents_company ON documents(company_id);
